export const nextGeneration = (liveCells: Cell[]): Cell[] => {
  const liveKeys = new Set(liveCells.map(keyOf));
  const candidates = new Map<string, { cell: Cell; count: number }>();

  for (const neighbor of liveCells.flatMap(neighborsOf)) {
    const key = keyOf(neighbor);
    const existing = candidates.get(key);
    if (existing) existing.count += 1;
    else candidates.set(key, { cell: neighbor, count: 1 });
  }

  return [...candidates]
    .filter(([key, { count }]) => survives(liveKeys.has(key), count))
    .map(([, { cell }]) => cell);
};

